tentSecurityPolicy::TRUSTED_TYPES_DIRECTIVE) {\n1427:     if (allows(CSP_NONE, EmptyString())) {\n1428:       // Step 2.4: if directive’s value only contains a tt-keyword which is a\n1429:       // match for a value 'none', set createViolation to true.\n1430:       // `nsCSPParser` ignores the 'none' keyword if other keywords or policy\n1431:       // names are present. Hence no additional checks required here.\n1432:       return true;\n1433:     }\n1434: \n1435:     if (aCreatedPolicyNames.Contains(aPolicyName) \u0026\u0026\n1436:         !allows(CSP_ALLOW_DUPLICATES, EmptyString())) {\n1437:       // Step 2.5: if createdPolicyNames contains policyName and directive’s\n1438:       // value does not contain a tt-keyword which is a match for a value\n1439:       // 'allow-duplicates', set createViolation to true.\n1440:       return true;\n1441:     }\n1442: \n1443:     if (!ContainsTrustedTypesDirectivePolicyName(aPolicyName) \u0026\u0026\n1444:         !ContainsTrustedTypesDirectivePolicyName(kWildcard)) {\n1445:       // Step 2.6: if directive’s value does not contain a tt-policy-name, which\n1446:       // value is policyName, and directive’s value does not contain a\n1447:       // tt-wildcard, set createViolation to true.\n1448:       return true;\n1449:     }\n1450:   }\n1451: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/firefox--871325b8@01dcdcebaca08ed5c32f8d50532752a063dc5ade/-/blob/dom/security/nsCSPUtils.cpp%3FL1380-1450"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1380:     }
