1385: // https://w3c.github.io/webappsec-csp/#allow-all-inline
1386: bool nsCSPDirective::allowsAllInlineBehavior(CSPDirective aDir) const {
1387:   // Step 1. Let allow all inline be false.
1388:   bool allowAll = false;
1389: 
1390:   // Step 2. For each expression of list:
1391:   for (nsCSPBaseSrc* src : mSrcs) {
1392:     // Step 2.1. If expression matches the nonce-source or hash-source grammar,
1393:     // return "Does Not Allow".
1394:     if (src->isNonce() || src->isHash()) {
1395:       return false;
1396:     }
1397: 
1398:     // Step 2.2. If type is "script", "script attribute" or "navigation" and
1399:     // expression matches the keyword-source "'strict-dynamic'", return "Does
1400:     // Not Allow".
1401:     if ((aDir == nsIContentSecurityPolicy::SCRIPT_SRC_ELEM_DIRECTIVE ||
1402:          aDir == nsIContentSecurityPolicy::SCRIPT_SRC_ATTR_DIRECTIVE) &&
1403:         src->isKeyword(CSP_STRICT_DYNAMIC)) {
1404:       return false;
1405:     }
1406: 
1407:     // Step 2.3. If expression is an ASCII case-insensitive match for the
1408:     // keyword-source "'unsafe-inline'", set allow all inline to true.
1409:     if (src->isKeyword(CSP_UNSAFE_INLINE)) {
1410:       allowAll = true;
1411:     }
1412:   }
1413: 
1414:   // Step 3. If allow all inline is true, return "Allows". Otherwise, return
1415:   // "Does Not Allow".
1416:   return allowAll;
1417: }
